<template>
  <div class="home">
    <!-- Banner 컴포넌트 -->
    <AppBanner :movie="featuredMovie" />

    <!-- MovieRow 컴포넌트들 -->
    <AppMovieRow title="인기 영화" :fetchUrl="popularMoviesUrl" />
    <AppMovieRow title="최신 영화" :fetchUrl="newReleasesUrl" />
    <AppMovieRow title="액션 영화" :fetchUrl="actionMoviesUrl" />
  </div>
</template>

<script setup>
import { ref, onMounted, onUnmounted } from "vue";
import { URLService } from "@/utils/movie/URL.js"; // 경로는 프로젝트 구조에 맞게 조정해야 합니다
import AppBanner from "@/views/HomeMain/Banner.vue"; // 경로는 프로젝트 구조에 맞게 조정해야 합니다
import AppMovieRow from "@/views/HomeMain/MovieRow.vue"; // 경로는 프로젝트 구조에 맞게 조정해야 합니다

const apiKey = ref(localStorage.getItem("TMDb-Key") || "");
const featuredMovie = ref(null);
const popularMoviesUrl = ref("");
const newReleasesUrl = ref("");
const actionMoviesUrl = ref("");

popularMoviesUrl.value = URLService.getURL4PopularMovies(apiKey.value);
newReleasesUrl.value = URLService.getURL4ReleaseMovies(apiKey.value);
actionMoviesUrl.value = URLService.getURL4GenreMovies(apiKey.value, "28");

const loadFeaturedMovie = async () => {
  featuredMovie.value = await URLService.fetchFeaturedMovie(apiKey.value);
};

const scrollListener = () => {
  const header = document.querySelector(".app-header");
  if (window.scrollY > 50) {
    header?.classList.add("scrolled");
  } else {
    header?.classList.remove("scrolled");
  }
};

onMounted(() => {
  loadFeaturedMovie();
  window.addEventListener("scroll", scrollListener);
});

onUnmounted(() => {
  window.removeEventListener("scroll", scrollListener);
});
</script>

<style scoped>
html,
body {
  overflow-y: scroll !important;
}

body {
  background-color: #141414 !important;
}
</style>
