<template>
  <div class="movie-grid" ref="gridContainer">
    <div :class="['grid-container', currentView]">
      <div
        v-for="(movieGroup, i) in visibleMovieGroups"
        :key="i"
        :class="['movie-row', { full: movieGroup.length === rowSize }]"
      >
        <div
          v-for="(movie, j) in movieGroup"
          :key="j"
          class="movie-card"
          @mouseup="toggleWishlist(movie)"
        >
          <img :src="getImageUrl(movie.poster_path)" :alt="movie.title" />
          <div class="movie-title">{{ movie.title }}</div>
          <div v-if="isInWishlist(movie.id)" class="wishlist-indicator">👍</div>
        </div>
      </div>
    </div>
    <div class="pagination" v-if="totalPages > 1">
      <button @click="prevPage" :disabled="currentPage === 1">&lt; 이전</button>
      <span>{{ currentPage }} / {{ totalPages }}</span>
      <button @click="nextPage" :disabled="currentPage === totalPages">
        다음 &gt;
      </button>
    </div>
  </div>
</template>

<script>
import axios from "axios";
import { ref, computed, onMounted, onBeforeUnmount } from "vue";

export default {
  name: "MovieGrid",
  props: {
    fetchUrl: {
      type: String,
      required: true,
    },
  },
  setup(props) {
    const gridContainer = (ref < HTMLElement) | (null > null);
    const movies = ref([]);
    const currentPage = ref(1);
    const rowSize = ref(4);
    const moviesPerPage = ref(20);
    const isMobile = ref(window.innerWidth <= 768);
    const currentView = ref("grid");
    const wishlist = ref(new Set());
    let wishlistTimer = null;

    const fetchMovies = async () => {
      try {
        const totalMoviesNeeded = 120;
        const numberOfPages = Math.ceil(
          totalMoviesNeeded / moviesPerPage.value
        );
        let allMovies = [];

        for (let page = 1; page <= numberOfPages; page++) {
          const response = await axios.get(props.fetchUrl, {
            params: {
              page,
              per_page: moviesPerPage.value,
            },
          });
          allMovies = [...allMovies, ...response.data.results];
        }

        movies.value = allMovies.slice(0, totalMoviesNeeded);
      } catch (error) {
        console.error("Error fetching movies:", error);
      }
    };

    const getImageUrl = (path) => `https://image.tmdb.org/t/p/w300${path}`;

    const visibleMovieGroups = computed(() => {
      const startIndex = (currentPage.value - 1) * moviesPerPage.value;
      const endIndex = startIndex + moviesPerPage.value;
      const paginatedMovies = movies.value.slice(startIndex, endIndex);

      return paginatedMovies.reduce((resultArray, item, index) => {
        const groupIndex = Math.floor(index / rowSize.value);
        if (!resultArray[groupIndex]) {
          resultArray[groupIndex] = [];
        }
        resultArray[groupIndex].push(item);
        return resultArray;
      }, []);
    });

    const totalPages = computed(() =>
      Math.ceil(movies.value.length / moviesPerPage.value)
    );

    const nextPage = () => {
      if (currentPage.value < totalPages.value) {
        currentPage.value++;
      }
    };

    const prevPage = () => {
      if (currentPage.value > 1) {
        currentPage.value--;
      }
    };

    const handleResize = () => {
      isMobile.value = window.innerWidth <= 768;
      calculateLayout();
    };

    const calculateLayout = () => {
      if (gridContainer.value) {
        const container = gridContainer.value;
        const containerWidth = container.offsetWidth;
        const containerHeight = window.innerHeight - container.offsetTop;
        const movieCardWidth = isMobile.value ? 90 : 200;
        const movieCardHeight = isMobile.value ? 150 : 220;
        const horizontalGap = isMobile.value ? 10 : 15;
        const verticalGap = -10;

        rowSize.value = Math.floor(
          containerWidth / (movieCardWidth + horizontalGap)
        );
        const maxRows = Math.floor(
          containerHeight / (movieCardHeight + verticalGap)
        );
        moviesPerPage.value = rowSize.value * maxRows;
      }
    };

    const toggleWishlist = (movie) => {
      if (wishlistTimer) clearTimeout(wishlistTimer);
      wishlistTimer = setTimeout(() => {
        if (wishlist.value.has(movie.id)) {
          wishlist.value.delete(movie.id);
        } else {
          wishlist.value.add(movie.id);
        }
      }, 300);
    };

    const isInWishlist = (movieId) => {
      return wishlist.value.has(movieId);
    };

    onMounted(() => {
      fetchMovies();
      calculateLayout();
      window.addEventListener("resize", handleResize);
    });

    onBeforeUnmount(() => {
      window.removeEventListener("resize", handleResize);
      if (wishlistTimer) clearTimeout(wishlistTimer);
    });

    return {
      gridContainer,
      movies,
      currentPage,
      rowSize,
      moviesPerPage,
      isMobile,
      currentView,
      fetchMovies,
      getImageUrl,
      visibleMovieGroups,
      totalPages,
      nextPage,
      prevPage,
      handleResize,
      calculateLayout,
      toggleWishlist,
      isInWishlist,
    };
  },
};
</script>

<style scoped>
