<template>
  <div class="popular-container">
    <div class="view-toggle">
      <button
        @click="setView('grid')"
        :class="{ active: currentView === 'grid' }"
      >
        <font-awesome-icon :icon="faTh" />
      </button>
      <button
        @click="setView('list')"
        :class="{ active: currentView === 'list' }"
      >
        <font-awesome-icon :icon="faBars" />
      </button>
    </div>

    <!-- MovieGrid 컴포넌트 -->
    <MovieGrid
      v-if="currentView === 'grid'"
      title="인기 영화"
      :fetchUrl="fetFetchURL()"
    />

    <!-- MovieInfiniteScroll 컴포넌트 -->
    <MovieInfiniteScroll
      v-if="currentView === 'list'"
      :apiKey="apiKey"
      genreCode="28"
      sortingOrder="all"
      voteEverage="-1"
    />
  </div>
</template>

<script setup>
import { ref, onMounted } from "vue";
import { FontAwesomeIcon } from "@fortawesome/vue-fontawesome";
import { faTh, faBars } from "@fortawesome/free-solid-svg-icons";
import MovieGrid from "@/views/views/MovieGrid.vue"; // 경로는 실제 프로젝트 구조에 맞게 수정하세요.
import MovieInfiniteScroll from "@/views/views/MovieInfiniteScrollComponent.vue"; // 경로는 실제 프로젝트 구조에 맞게 수정하세요.
import { URLService } from "@/utils/movie/URL"; // 경로는 실제 프로젝트 구조에 맞게 수정하세요.

const apiKey = ref(localStorage.getItem("TMDb-Key") || "");
const currentView = ref("grid");

const fetFetchURL = () => {
  return URLService.getURL4PopularMovies(apiKey.value);
};

const setView = (view) => {
  currentView.value = view;
  if (view === "grid") {
    disableScroll();
  } else {
    enableScroll();
  }
};

const disableScroll = () => {
  document.body.style.overflow = "hidden";
};

const enableScroll = () => {
  document.body.style.overflow = "auto";
};

onMounted(() => {
  disableScroll();
});
</script>

<style scoped>
.view-toggle {
  display: flex;
  justify-content: flex-end;
  margin-top: 50px;
}

.view-toggle button {
  background-color: #333;
  color: white;
  border: none;
  padding: 10px 15px;
  margin-left: 10px;
  cursor: pointer;
  border-radius: 4px;
}

.view-toggle button.active {
  background-color: #535bf2;
}

@media (max-width: 768px) {
  .view-toggle {
    margin-top: 80px;
  }
}
</style>
