<template>
  <div class="movie-grid" ref="gridContainer">
    <div :class="['grid-container', currentView]">
      <div
        v-for="(movieGroup, i) in visibleMovieGroups"
        :key="i"
        :class="['movie-row', { full: movieGroup.length === rowSize }]"
      >
        <div
          v-for="(movie, j) in movieGroup"
          :key="j"
          class="movie-card"
          @mouseup="toggleWishlist(movie)"
        >
          <img :src="getImageUrl(movie.poster_path)" :alt="movie.title" />
          <div class="movie-title">{{ movie.title }}</div>
          <div v-if="isInWishlist(movie.id)" class="wishlist-indicator">👍</div>
        </div>
      </div>
    </div>

    <!-- Loading Trigger -->
    <div ref="loadingTrigger" class="loading-trigger">
      <div v-if="isLoading" class="loading-indicator">Loading...</div>
    </div>

    <!-- Scroll to Top Button -->
    <button
      v-if="showTopButton"
      @click="scrollToTopAndReset()"
      class="top-button"
    >
      Top
    </button>
  </div>
</template>

<script>
import { ref, onMounted, onBeforeUnmount } from "vue";

export default {
  name: "MovieInfiniteScroll",
  setup() {
    const gridContainer = ref(null);
    const loadingTrigger = ref(null);
    const visibleMovieGroups = ref([]);
    const currentView = ref("grid");
    const isLoading = ref(false);
    const showTopButton = ref(false);
    const rowSize = ref(4);

    // 영화 가져오기 시뮬레이션
    const fetchMovies = () => {
      // 여기에 가져오기 로직 구현
      isLoading.value = true;
      setTimeout(() => {
        // 로딩 완료 시뮬레이션
        isLoading.value = false;
      }, 2000);
    };

    const getImageUrl = (path) => {
      return `https://image.tmdb.org/t/p/w300${path}`;
    };

    const toggleWishlist = (movie) => {
      // 위시리스트 토글 로직 구현
      console.log(`영화 위시리스트 토글: ${movie.title}`);
    };

    const isInWishlist = (movieId) => {
      // 영화가 위시리스트에 있는지 확인
      return movieId % 2 === 0; // 예시 로직: 짝수 ID만 위시리스트에 있다고 가정
    };

    const scrollToTopAndReset = () => {
      window.scrollTo({ top: 0, behavior: "smooth" });
      // 여기에 리셋 로직 구현
    };

    onMounted(() => {
      fetchMovies();
      window.addEventListener("scroll", handleScroll);
    });

    onBeforeUnmount(() => {
      window.removeEventListener("scroll", handleScroll);
    });

    const handleScroll = () => {
      showTopButton.value = window.scrollY > 300;
    };

    return {
      gridContainer,
      loadingTrigger,
      visibleMovieGroups,
      currentView,
      isLoading,
      showTopButton,
      rowSize,
      fetchMovies,
      getImageUrl,
      toggleWishlist,
      isInWishlist,
      scrollToTopAndReset,
    };
  },
};
</script>

<style scoped>
/* 여기에 스타일 추가 */
.movie-grid {
  width: 100%;
}

.movie-card:hover {
  transform: scale(1.05);
}

.loading-trigger {
  text-align: center;
}

.top-button {
  position: fixed;
  bottom: 20px;
  right: 20px;
}
</style>
