import { createRouter, createWebHashHistory } from "vue-router";
import Home from "../views/Home.vue";
import SignIn from "../components/SignIn.vue";
import HomeMain from "../components/home/MainHomeComponent.vue";
import HomeWishlist from "../components/home/WishlistHomeComponent.vue";
import HomeSearch from "../components/Search.vue";
import HomePopular from "../components/home/PopularHomeComponent.vue";

const routes = [
  {
    path: "/",
    component: Home,
    children: [
      { path: "", component: HomeMain },
      { path: "popular", component: HomePopular },
      { path: "wishlist", component: HomeWishlist },
      { path: "search", component: HomeSearch },
    ],
    meta: { requiresAuth: true },
  },
  {
    path: "/SignIn",
    component: SignIn,
  },
];

const router = createRouter({
  history: createWebHashHistory(),
  routes,
});

router.beforeEach((to, from, next) => {
  if (to.matched.some((record) => record.meta.requiresAuth)) {
    const isAuthenticated = localStorage.getItem("TMDb-Key") !== null;
    if (!isAuthenticated) {
      next("/SignIn");
    } else {
      next();
    }
  } else {
    next();
  }
});

export default router;
