<template>
  <div class="movie-row">
    <h2>{{ title }}</h2>
    <div
      class="slider-container"
      @wheel="handleWheel"
      @touchstart="handleTouchStart"
      @touchmove="handleTouchMove"
      @touchend="handleTouchEnd"
      @mousemove="handleMouseMove"
      @mouseleave="handleMouseLeave"
    >
      <button
        class="slider-button left"
        @click="slide('left')"
        :style="{ opacity: showButtons && !atLeftEdge ? 1 : 0 }"
        :disabled="atLeftEdge"
      >
        &lt;
      </button>
      <div class="slider-window" ref="sliderWindow">
        <div
          class="movie-slider"
          ref="slider"
          :style="{ transform: `translateX(${-scrollAmount}px)` }"
        >
          <div
            v-for="movie in movies"
            :key="movie.id"
            class="movie-card"
            @click="toggleWishlist(movie)"
          >
            <img
              :src="getImageUrl(movie.poster_path)"
              :alt="movie?.title || 'Movie poster'"
            />
            <div v-if="isInWishlist(movie.id)" class="wishlist-indicator">
              👍
            </div>
          </div>
        </div>
      </div>
      <button
        class="slider-button right"
        @click="slide('right')"
        :style="{ opacity: showButtons && !atRightEdge ? 1 : 0 }"
        :disabled="atRightEdge"
      >
        &gt;
      </button>
    </div>
  </div>
</template>

<script>
import { ref, onMounted, onBeforeUnmount, computed, nextTick } from "vue";
import axios from "axios";
import { useWishlist } from "@/utils/movie/wishlist"; // 경로는 실제 프로젝트 구조에 맞게 조정해야 합니다

export default {
  name: "MovieRow",
  props: {
    title: {
      type: String,
      required: true,
    },
    fetchUrl: {
      type: String,
      required: true,
    },
  },
  setup(props) {
    const slider = (ref < HTMLElement) | (null > null);
    const sliderWindow = (ref < HTMLElement) | (null > null);
    const movies = ref([]);
    const scrollAmount = ref(0);
    const showButtons = ref(false);
    const isScrolling = ref(false);
    const touchStartX = ref(0);
    const touchEndX = ref(0);
    const maxScroll = ref(0);

    const wishlistService = useWishlist();

    const atLeftEdge = computed(() => scrollAmount.value <= 0);
    const atRightEdge = computed(() => scrollAmount.value >= maxScroll.value);

    const fetchMovies = async () => {
      try {
        const response = await axios.get(props.fetchUrl);
        movies.value = response.data.results;
        console.log(movies.value);
        await nextTick();
        calculateMaxScroll();
      } catch (error) {
        console.error("Error fetching movies:", error);
      }
    };

    const getImageUrl = (path) => {
      return `https://image.tmdb.org/t/p/w300${path}`;
    };

    const slide = (direction, amount = null) => {
      const slideAmount = amount || sliderWindow.value.clientWidth * 0.8;
      if (direction === "left") {
        scrollAmount.value = Math.max(0, scrollAmount.value - slideAmount);
      } else {
        scrollAmount.value = Math.min(
          maxScroll.value,
          scrollAmount.value + slideAmount
        );
      }
    };

    const handleMouseMove = () => {
      showButtons.value = true;
    };

    const handleMouseLeave = () => {
      showButtons.value = false;
    };

    const handleWheel = (event) => {
      event.preventDefault();
      if (isScrolling.value) return;

      isScrolling.value = true;
      const direction = event.deltaY > 0 ? "right" : "left";
      slide(direction);

      setTimeout(() => {
        isScrolling.value = false;
      }, 500);
    };

    const handleTouchStart = (event) => {
      touchStartX.value = event.touches[0].clientX;
      touchEndX.value = event.touches[0].clientX;
    };

    const handleTouchMove = (event) => {
      touchEndX.value = event.touches[0].clientX;
    };

    const handleTouchEnd = () => {
      const touchDiff = touchStartX.value - touchEndX.value;
      const minSwipeDistance = 50;

      if (Math.abs(touchDiff) > minSwipeDistance) {
        const direction = touchDiff > 0 ? "right" : "left";
        slide(direction, Math.abs(touchDiff));
      }
    };

    const calculateMaxScroll = () => {
      if (slider.value && sliderWindow.value) {
        maxScroll.value = Math.max(
          0,
          slider.value.scrollWidth - sliderWindow.value.clientWidth
        );
      }
    };

    const handleResize = () => {
      calculateMaxScroll();
      scrollAmount.value = Math.min(scrollAmount.value, maxScroll.value);
    };

    const toggleWishlist = (movie) => {
      wishlistService.toggleWishlist(movie);
    };

    const isInWishlist = (movieId) => {
      return wishlistService.isInWishlist(movieId);
    };

    onMounted(() => {
      fetchMovies();
      window.addEventListener("resize", handleResize);
    });

    onBeforeUnmount(() => {
      window.removeEventListener("resize", handleResize);
    });

    return {
      movies,
      scrollAmount,
      showButtons,
      slider,
      sliderWindow,
      atLeftEdge,
      atRightEdge,
      getImageUrl,
      slide,
      handleMouseMove,
      handleMouseLeave,
      handleWheel,
      handleTouchStart,
      handleTouchMove,
      handleTouchEnd,
      toggleWishlist,
      isInWishlist,
    };
  },
};
</script>

<style scoped>
/* movie-row.component.css 내용을 여기에 추가 */
.movie-row h2 {
  text-align: left;
  margin-left: 30px;
}
