<template>
  <div
    v-if="movie"
    class="banner"
    :style="{ backgroundImage: 'url(' + backdropUrl + ')' }"
  >
    <div class="banner-content">
      <h1>{{ movieTitle }}</h1>
      <p>{{ movieOverview }}</p>
      <button class="play-btn title-btn">재생</button>
      <button class="info-btn title-btn">상세 정보</button>
    </div>
  </div>
</template>

<script>
export default {
  name: "MovieBanner",
  props: {
    movie: {
      type: Object,
      required: true,
    },
  },
  computed: {
    backdropUrl() {
      if (this.movie && "backdrop_path" in this.movie) {
        return `https://image.tmdb.org/t/p/original${this.movie.backdrop_path}`;
      }
      return "";
    },
    movieTitle() {
      return this.movie?.title || "No Title";
    },
    movieOverview() {
      const { overview = "No Overview" } = this.movie || {};
      return overview;
    },
  },
};
</script>

