// src/composables/useWishlist.js
import { ref, computed, watch } from "vue";

export function useWishlist() {
  const wishlist = ref([]);

  // 로컬 스토리지에서 위시리스트 로드
  const loadWishlist = () => {
    const storedWishlist = localStorage.getItem("movieWishlist");
    if (storedWishlist) {
      wishlist.value = JSON.parse(storedWishlist);
    }
  };

  // 위시리스트를 로컬 스토리지에 저장
  const saveWishlist = () => {
    localStorage.setItem("movieWishlist", JSON.stringify(wishlist.value));
  };

  // 위시리스트 변경 시 자동 저장
  watch(wishlist, saveWishlist, { deep: true });

  // 초기 로드
  loadWishlist();

  const toggleWishlist = (movie) => {
    const index = wishlist.value.findIndex((item) => item.id === movie.id);
    if (index === -1) {
      // 영화가 위시리스트에 없으면 추가
      wishlist.value.push(movie);
    } else {
      // 영화가 이미 위시리스트에 있으면 제거
      wishlist.value.splice(index, 1);
    }
  };

  const isInWishlist = (movieId) => {
    return wishlist.value.some((item) => item.id === movieId);
  };

  const getCurrentWishlist = computed(() => wishlist.value);

  return {
    wishlist,
    toggleWishlist,
    isInWishlist,
    getCurrentWishlist,
  };
}
