<template>
  <div class="dropdown-container">
    <label>선호하는 설정을 선택하세요</label>
    <div
      v-for="(dropdown, index) in dropdownEntries"
      :key="index"
      class="custom-select"
    >
      <div class="select-selected" @click="toggleDropdown(dropdown.key)">
        {{ selectedOptions[dropdown.key] }}
        <span class="select-arrow">{{
          activeDropdown === dropdown.key ? "▲" : "▼"
        }}</span>
      </div>
      <div v-if="activeDropdown === dropdown.key" class="select-items">
        <div
          v-for="(option, idx) in dropdown.options"
          :key="idx"
          @click="selectOption(dropdown.key, option)"
        >
          {{ option }}
        </div>
      </div>
    </div>
    <button class="clear-options" @click="clearOptions">초기화</button>
  </div>
</template>

<script>
import { ref } from "vue";

export default {
  name: "MovieSearch",
  emits: ["changeOptions"],
  setup(props, { emit }) {
    const dropdowns = {
      originalLanguage: [
        "장르 (전체)",
        "Action",
        "Adventure",
        "Comedy",
        "Crime",
        "Family",
      ],
      translationLanguage: [
        "평점 (전체)",
        "9~10",
        "8~9",
        "7~8",
        "6~7",
        "5~6",
        "4~5",
        "4점 이하",
      ],
      sorting: ["언어 (전체)", "영어", "한국어"],
    };

    const DEFAULT_OPTIONS = {
      originalLanguage: "장르 (전체)",
      translationLanguage: "평점 (전체)",
      sorting: "언어 (전체)",
    };

    const selectedOptions = ref({ ...DEFAULT_OPTIONS });
    const activeDropdown = ref(null);

    const dropdownEntries = Object.entries(dropdowns).map(([key, options]) => ({
      key,
      options,
    }));

    const toggleDropdown = (key) => {
      activeDropdown.value = activeDropdown.value === key ? null : key;
    };

    const selectOption = (key, option) => {
      selectedOptions.value[key] = option;
      activeDropdown.value = null;
      emit("changeOptions", { ...selectedOptions.value });
    };

    const clearOptions = () => {
      selectedOptions.value = { ...DEFAULT_OPTIONS };
      emit("changeOptions", { ...selectedOptions.value });
    };

    return {
      dropdownEntries,
      selectedOptions,
      activeDropdown,
      toggleDropdown,
      selectOption,
      clearOptions,
    };
  },
};
</script>

